// ================================================================
//  EXPORT ENGINE (HTML / PDF / Word)
// ================================================================

function exportHTML() {
  var name = document.getElementById('baziNameOut') ? document.getElementById('baziNameOut').textContent : '乾元命理报告';
  var meta = document.getElementById('baziMetaOut') ? document.getElementById('baziMetaOut').textContent : '';
  var html = '<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><title>'+name+'</title>';
  html += '<style>body{font-family:"Songti SC","SimSun",serif;max-width:800px;margin:0 auto;padding:40px 20px;background:#fff;color:#333;line-height:1.8}'
  html += 'h1{text-align:center;color:#8B6914;border-bottom:2px solid #D4AF37;padding-bottom:16px}'
  html += 'h2{color:#8B6914;margin-top:32px;border-left:4px solid #D4AF37;padding-left:12px}'
  html += 'table{width:100%;border-collapse:collapse;margin:16px 0}'
  html += 'td,th{padding:8px 12px;border:1px solid #e0d0a0;text-align:center}'
  html += '.gang{display:flex;justify-content:center;gap:8px;margin:16px 0;font-size:28px}'
  html += '.gz{background:#fdf6e3;padding:8px 16px;border-radius:8px;text-align:center}'
  html += '.g,.z{font-size:28px}'
  html += '.warn{background:#fff3cd;border:1px solid #ffc107;padding:16px;border-radius:8px;margin:16px 0}'
  html += '.section{margin:24px 0;padding:20px;background:#fafafa;border-radius:8px}'
  html += 'h3{color:#8B6914;margin-top:0}'
  html += 'ul{padding-left:24px}'
  html += 'li{margin:6px 0}'
  html += 'footer{text-align:center;color:#999;font-size:12px;margin-top:40px;padding-top:20px;border-top:1px solid #eee}'
  html += '</style></head><body>';
  html += '<h1>'+name+'</h1>';
  if (meta) html += '<p style="text-align:center;color:#888;margin-top:-16px">'+meta+'</p>';

  // Pillar
  var pillerDiv = document.querySelector('.pillar-render') || document.querySelector('.baZi-output');
  if (pillerDiv) {
    html += '<div class="section"><h2>四柱八字</h2>';
    html += '<div class="gang">';
    for (var i=0;i<4;i++){
      var g=document.getElementById('bz'+i+'g');var z=document.getElementById('bz'+i+'z');
      if(g&&z) html+='<div class="gz"><div class="g">'+g.textContent+'</div><div class="z">'+z.textContent+'</div></div>';
    }
    html += '</div></div>';
  }

  // Analysis
  var cards = document.querySelectorAll('.analysis-card');
  if (cards.length > 0) {
    html += '<div class="section"><h2>命理分析</h2>';
    cards.forEach(function(c){
      var h=c.querySelector('h5');var p=c.querySelector('p');
      if(h&&p) html += '<h3>'+h.textContent+'</h3><p>'+p.textContent+'</p>';
    });
    html += '</div>';
  }

  // Warnings
  var warns = document.querySelectorAll('.warning-box,.risk-alert,.bazi-warn');
  if (warns.length > 0) {
    html += '<div class="warn"><h2 style="margin-top:0;border:none;padding:0">⚠️ 重点注意事项</h2>';
    warns.forEach(function(w){ html += '<p>'+w.textContent+'</p>'; });
    html += '</div>';
  }

  // Five elements bar
  var bar = document.getElementById('eleBar');
  if (bar) {
    var segs = bar.querySelectorAll('.ele-seg');
    if (segs.length > 0) {
      html += '<div class="section"><h2>五行分布</h2><div style="display:flex;height:24px;border-radius:12px;overflow:hidden">';
      segs.forEach(function(s){ html += '<div style="width:'+s.style.width+';background:'+s.style.background+';min-height:24px"></div>'; });
      html += '</div></div>';
    }
  }

  html += '<footer>易道智鉴 · 命理报告 · 生成时间：'+new Date().toLocaleString('zh-CN')+'</footer>';
  html += '<\/body><\/html>';

  downloadBlob(html, name+'.html', 'text/html;charset=utf-8');
  showToast('HTML 报告已下载');
}

function exportPDF() {
  exportHTML();
  setTimeout(function(){ showToast('HTML 已下载，请用浏览器打印为 PDF（Ctrl+P → 另存为PDF）'); }, 500);
}

function downloadBlob(content, filename, mimeType) {
  var blob = new Blob([content], {type: mimeType});
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function exportCurrentSection() {
  var btns = document.querySelectorAll('.nav-btn');
  var active = null;
  for (var i = 0; i < btns.length; i++) { if (btns[i].classList.contains('active')) { active = btns[i]; break; } }
  if (!active) { showToast('请先选择一个功能模块'); return; }
  var sectionId = active.getAttribute('data-section');
  var section = document.getElementById(sectionId);
  if (!section) { showToast('未找到对应内容'); return; }
  var html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>导出</title><style>body{font-family:sans-serif;max-width:800px;margin:0 auto;padding:20px;background:#0a0a0a;color:#f0e8d8}h1{color:#c9a84c}</style></head><body>' + section.innerHTML + '</body></html>';
  downloadBlob(html, '导出内容.html', 'text/html;charset=utf-8');
  showToast('已导出当前模块');
}


// ===== 商城分类切换 =====
function showShopCategory(name, btn) {
  // 切换标签状态
  document.querySelectorAll('.shop-tab').forEach(t => t.classList.remove('active'));
  if (btn) btn.classList.add('active');
  
  // 切换面板显示
  document.querySelectorAll('.shop-panel').forEach(p => p.style.display = 'none');
  var panel = document.getElementById('shopPanel-' + name);
  if (panel) panel.style.display = 'block';
  
  // 懒加载数据
  if (name === 'daoyi' && document.getElementById('daoyi-grid').children.length === 0) {
    renderDaoyiProducts();
  } else if (name === 'foyi' && document.getElementById('foyi-grid').children.length === 0) {
    renderFoyiProducts();
  } else if (name === 'masters' && document.getElementById('masters-grid').children.length === 0) {
    renderMasters();
  }
}

// ===== 渲染道医产品 =====
function renderDaoyiProducts() {
  var grid = document.getElementById('daoyi-grid');
  if (!grid || typeof DAO_MEDICINE === 'undefined') return;
  
  DAO_MEDICINE.forEach(function(item) {
    var card = document.createElement('div');
    card.className = 'medicine-card';
    card.style.cssText = 'background:rgba(255,255,255,0.03);border:1px solid rgba(201,168,76,0.2);border-radius:12px;overflow:hidden;cursor:pointer;transition:all .3s';
    card.onmouseover = function() { this.style.borderColor='rgba(201,168,76,0.5)';this.style.transform='translateY(-4px)' };
    card.onmouseout = function() { this.style.borderColor='rgba(201,168,76,0.2)';this.style.transform='translateY(0)' };
    card.onclick = function() { showMedicineDetail(item) };
    
    card.innerHTML = 
      '<div style="height:100px;background:linear-gradient(135deg,rgba(201,168,76,0.12),rgba(201,168,76,0.03));display:flex;align-items:center;justify-content:center;font-size:48px">' + item.image + '</div>' +
      '<div style="padding:16px">' +
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">' +
          '<span style="font-size:14px;color:var(--gold);font-weight:bold">' + item.name + '</span>' +
          '<span style="font-size:11px;background:rgba(201,168,76,0.15);color:var(--gold);padding:2px 8px;border-radius:10px">' + item.school + '</span>' +
        '</div>' +
        '<p style="font-size:12px;color:var(--paper2);margin-bottom:10px;line-height:1.6">' + item.desc + '</p>' +
        '<div style="display:flex;justify-content:space-between;align-items:center">' +
          '<span style="font-size:16px;color:var(--gold)">¥' + item.price + '</span>' +
          '<span style="font-size:11px;opacity:.5">' + item.master + '</span>' +
        '</div>' +
      '</div>';
    
    grid.appendChild(card);
  });
}

