  html += getDimensionAdvice(hj);
  html += '</div>';

  // 化煞道观寺庙推荐
  html += '<div class="huajie-block">';
  html += '<h5>🏛️ 化煞道观寺庙推荐</h5>';
  html += getTempleRecommendation(hj);
  html += '</div>';

  out.innerHTML = html;
  out.style.display = 'block';
  out.classList.add('visible');
  out.scrollIntoView({ behavior: 'smooth' });
