function computeQimen() {
  playDivinationSound();
  const dateStr = document.getElementById('qmDate').value;
  const hourVal = document.getElementById('qmHour').value;
  const name = document.getElementById('qmName').value || '有缘人';
  const dunVal = document.getElementById('qmDun').value;
  if (!dateStr || !hourVal) { showToast('请输入日期和时辰'); return; }
  const [year, month, day] = dateStr.split('-').map(Number);
  const hourNum = parseInt(hourVal);

  // Derive basic stems/branches
  const dayStemIdx = getDayStemIndex(year, month, day);
  const dayBranchIdx = getDayBranchIndex(year, month, day);
  const dayStem = STEMS[dayStemIdx];
  const dayBranch = BRANCHES[dayBranchIdx];
  const hourBranchIdx = Math.floor(hourNum / 2) % 12;
  const hourBranch = BRANCHES[hourBranchIdx];
  const hourStemIdx = getHourStem(dayStemIdx, hourBranch);
  const hourStem = STEMS[hourStemIdx];

  // Yin/Yang Dun
  const isYang = month >= 11 || month <= 4;
  const isYangDun = dunVal === 'yang' || (dunVal === 'auto' && isYang);
  const rotate = isYangDun ? [1,2,3,4,5,6,7,8,9] : [9,8,7,6,5,4,3,2,1];

  // Key palace based on day stem
  const keyPalaceBase = STEM_KEYS.indexOf(dayStem) + 1;
  const keyPalace = keyPalaceBase > 0 ? keyPalaceBase : 5;

  // Build palaces
  const palaces = {};
  for (let i = 0; i < 9; i++) {
    const p宫 = rotate[i];
    palaces[p宫] = { num: p宫, ...PALACE_INFO[p宫] };
  }

  // Distribute stars (蓬芮任冲辅英禽心柱)
  const starNames = ['蓬','芮','任','冲','辅','英','禽','心','柱'];
  const starKeyMap = {'蓬':'pei','芮':'yin','任':'ying','冲':'chu','辅':'fang','英':'you','禽':'jin','心':'zhen','柱':'rong'};
  const starStart = (keyPalace - 1 + (isYangDun ? 0 : 8)) % 9;
  for (let i = 0; i < 9; i++) {
    const p宫 = rotate[i];
    const sIdx = (starStart + i) % 9;
    palaces[p宫].star = STARS_MAP[starKeyMap[starNames[sIdx]]];
  }

  // Distribute doors
  const doorNames = ['休','开','生','伤','杜','景','死','惊'];
  const doorKeyMap = {'休':'xin','开':'kai','生':'sheng','伤':'shang','杜':'du','景':'jing','死':'si','惊':'cun'};
  const doorStart = (keyPalace - 1 + (isYangDun ? 0 : 8)) % 8;
  let doorPos = 0;
  for (let i = 0; i < 9; i++) {
    const p宫 = rotate[i];
    if (p宫 === 5) { palaces[p宫].door = DOORS_MAP.jin; continue; }
    const dIdx = (doorStart + doorPos) % 8;
    palaces[p宫].door = DOORS_MAP[doorKeyMap[doorNames[dIdx]]];
    doorPos++;
  }

  // Distribute gods
  const godNames = ['符','龙','冲','辅','英','芮','柱','心'];
  const godKeyMap = {'符':'zhi','龙':'long','冲':'chu','辅':'fang','英':'ying','芮':'yin','柱':'rong','心':'zhen'};
  const godStart = (keyPalace - 1 + (isYangDun ? 0 : 8)) % 8;
  let godPos = 0;
  for (let i = 0; i < 9; i++) {
    const p宫 = rotate[i];
    if (p宫 === 5) { palaces[p宫].god = GODS_MAP.long; continue; }
    const gIdx = (godStart + godPos) % 8;
    palaces[p宫].god = GODS_MAP[godKeyMap[godNames[gIdx]]];
    godPos++;
  }

  palaces[5].star = STARS_MAP.jin;
  palaces[5].door = DOORS_MAP.jin;
  palaces[5].god = GODS_MAP.long;

  const keyPalaceData = palaces[keyPalace];
  const jiuxing = keyPalaceData?.star?.name || '天心';
  const bamen = keyPalaceData?.door?.name || '开门';
  const bashen = keyPalaceData?.god?.name || '值符';

  // RENDER - 动态九宫格盘面
  document.getElementById('qmMeta').textContent = `奇门遁甲 · ${dayStem}日 · 时支${hourBranch}`;
  document.getElementById('qmSub').textContent = `${isYangDun ? '阳遁' : '阴遁'} · ${jiuxing}星临${PALACE_INFO[keyPalace].name} · ${bamen}为值使`;

  const grid = document.getElementById('qmGrid');
  grid.innerHTML = '';
  const cellOrder = [4,9,2,3,5,7,8,1,6];
  const starColors = {大吉:'#2ecc71',吉:'#27ae60',平:'#f39c12',小凶:'#e67e22',次凶:'#e74c3c',凶:'#c0392b',大凶:'#c0392b'};

  cellOrder.forEach((p宫) => {
    const p = palaces[p宫];
    const div = document.createElement('div');
    div.className = 'qn-cell' + (p宫 === 5 ? ' center-cell' : '');
    const sc = starColors[p.star?.type] || '#95a5a6';
    const dc = p.door?.color || '#95a5a6';
    div.innerHTML = `
      <p class="qn-pos">${p宫===5?'中宫':p宫+'宫'}</p>
      <p class="qn-star" style="color:${sc}">${p.star?.name||''}</p>
      <p class="qn-door" style="color:${dc}">${p.door?.name||''}门</p>
      <p class="qn-god">${p.god?.name||''}</p>
      <p class="qn-analysis">${getComboText(p.star?.name, p.door?.name)}</p>
    `;
    grid.appendChild(div);
  });

  // Interpretation
  const ctr = document.getElementById('qmInterp');
  ctr.innerHTML = '';
  const kp = PALACE_INFO[keyPalace];
  const isGood = palaces[keyPalace].star?.type === '大吉' || palaces[keyPalace].star?.type === '吉';
  const ov = `此局为${isYangDun?"阳遁":"阴遁"},${jiuxing}星临${kp.name||'中宫'},${bamen}门为值使，${bashen}神护卫。${isGood?"星门皆吉，大象有利。":"星门带凶，行事宜守不宜动。"}`;

  const intCards = [
    { title:'全 局 论 断', text: ov, accent:'violet-accent' },
    { title:'值 使 宫 位', text: `${kp.name}·${jiuxing}星·${bamen}门·${bashen}神。${getDoorAdvice(bamen)}`, accent:'gold-accent' },
    { title:'星 门 吉 凶', text: getPalaceSummary(palaces), accent:'jade-accent' },
    { title:'时 机 方 位', text: `${isYangDun?"阳遁":"阴遁"}利在${isYangDun?"阳时阳方":"阴时阴方"}。${kp.dir}为吉方，当${kp.ele}属性之事。`, accent:'cyan-accent' },
    { title:'宜 忌 策 略', text: getYiJi(palaces, keyPalace), accent:'cinn-accent' },
    { title:'📜 经典出处', text: '《奇门遁甲秘笈》云:「奇门遁甲者，天地之数，阴阳之理，造化之机也。」《烟波钓叟歌》曰:「阴阳顺逆妙难穷，二至还乡一九宫。若能了达阴阳理，天地都来一掌中。」《阳遁九局》载:「阳遁九局，阴遁九局，共十八局，天地之数尽在其中。」', accent:'gold-accent' },
  ];
  for (const c of intCards) {
    const div = document.createElement('div');
    div.className = 'interp-card ' + c.accent;
    div.innerHTML = `<h5>${c.title}</h5><p>${c.text}</p>`;
    ctr.appendChild(div);
  }
  
  // 起心动念时辰分析（仅事盘）
  if (yjMode === 'matter' && yjQixinTime) {
    const qxBox = document.createElement('div');
    qxBox.className = 'interp-card gold-accent';
    qxBox.style.marginTop = '20px';
    const qxDate = new Date(yjQixinTime);
    const qxLunar = getLunarDateStr(qxDate); // 需要农历转换
    qxBox.innerHTML = `
      <h5>☰ 起心动念时辰分析</h5>
      <p style="margin-bottom:10px">您于 <strong>${qxDate.toLocaleString('zh-CN')}</strong> 心生疑问（${qxLunar}）</p>
      <p style="margin-bottom:10px">《黄金策》云:「占卜之道，心诚则灵，时到则应。」起心动念之时，正是天机显现之刻。此时辰与卦象相参，可断事之吉凶、时之迟速。</p>
      <p>时辰${getShiChen(qxDate.getHours())}，${getShiChenAnalysis(qxDate.getHours(), hexNum)}</p>
    `;
    ctr.appendChild(qxBox);
  }

  // 奇门宫位解读
  var qmReadBox = document.getElementById('qmReadingBox');
  if (qmReadBox) qmReadBox.innerHTML = getQimenReadingHTML(keyPalace);

  // 主客判断（大白话总结）
  var qimenGuestHost = '<div style="margin-top:16px;padding:12px 16px;background:rgba(155,89,182,.04);border-left:3px solid #9b59b6;border-radius:0 8px 8px 0">';
  qimenGuestHost += '<div style="font-size:13px;font-weight:bold;color:#9b59b6;margin-bottom:8px">🏺 主客判断</div>';
  qimenGuestHost += '<div style="font-size:12px;color:var(--paper);line-height:1.8">';
  qimenGuestHost += '<strong style="color:var(--gold)">你是主方：</strong>先行动者为主，后发者受制于人。';
  qimenGuestHost += '若占问合作或竞争，建议<strong>后发制人</strong>，观察对方动向后再出手。';
  qimenGuestHost += '若占问健康或灾害，建议<strong>主动化解</strong>，不要被动等待。<br><br>';
  qimenGuestHost += '<strong style="color:var(--gold)">吉门（开休生）临身：</strong>诸事顺遂，可积极进取。<br>';
  qimenGuestHost += '<strong style="color:var(--gold)">凶门（死伤惊）临身：</strong>须谨慎行事，忌冒进。<br>';
  qimenGuestHost += '<strong style="color:var(--gold)">门迫宫：</strong>门克宫为门迫，做事多阻碍，需迂回而行。';
  qimenGuestHost += '</div></div>';
  if (qmReadBox) qmReadBox.innerHTML += qimenGuestHost;

  document.getElementById('qmResult').classList.add('visible');
  document.getElementById('qmResult').scrollIntoView({ behavior: 'smooth' });
}

const STEM_KEYS = ['甲','乙','丙','丁','戊','己','庚','辛','壬','癸'];

function getComboText(star, door) {
  if (!star || !door) return '';
  const combos = {
    '蓬-生':'破中求财', '蓬-开':'破财事业', '蓬-死':'极凶破财', '蓬-伤':'大凶伤身',
    '芮-生':'病中求医', '芮-死':'病重难愈', '芮-杜':'病情不明',
    '冲-伤':'冲动是非', '冲-杜':'变动受阻', '冲-生':'动而有得',
    '辅-生':'大吉学业', '辅-开':'大吉升迁', '辅-景':'文采飞扬',
    '心-生':'医卜求财', '心-开':'领导升迁', '心-休':'休养得法',
    '柱-开':'破败事业', '柱-生':'破败求财', '柱-死':'极凶破败',
    '英-景':'是非口舌', '英-开':'名声受损',
  };
  return combos[`${star}-${door}`] || `${star}会${door}门`;
}

function getDoorAdvice(door) {
  const m = {
    '生':'宜求财创业置产，大有可为','开':'宜事业升迁远行，开创新局',
    '休':'宜休养人际访友，以静制动','景':'宜文书信息告白，文事为佳',
    '伤':'宜讨债博弈，不宜大举进攻','杜':'宜保密躲藏，不宜张扬',
    '死':'宜丧葬捕猎，不宜轻动','惊':'宜官非诉讼，须防口舌',
  };
  return m[door] || '值使之门';
}

function getPalaceSummary(palaces) {
  let s = '';
  for (let p = 1; p <= 9; p++) {
    const pk = palaces[p];
    if (!pk || p === 5) continue;
    s += `${pk.name}:${pk.star?.name||''}·${pk.door?.name||''}门(${pk.star?.type||''})\n`;
  }
  return s;
}

function getYiJi(palaces, kp) {
  const good = Object.values(palaces).filter(p => p?.star?.type === '大吉' || p?.star?.type === '吉');
  const bad = Object.values(palaces).filter(p => p?.star?.type === '大凶' || p?.star?.type === '凶');
  return `宜:${good.map(p=>p.name).join('、')}。忌:${bad.map(p=>p.name).join('、')}。值使宫${palaces[kp]?.name||'中宫'}为行动核心。`;
}

