const LR_ZHI_GAN = {
  '子':{gan:'甲',ele:'水'},'丑':{gan:'乙',ele:'土'},'寅':{gan:'丙',ele:'木'},'卯':{gan:'甲',ele:'木'},
  '辰':{gan:'戊',ele:'土'},'巳':{gan:'丙',ele:'火'},'午':{gan:'丁',ele:'火'},'未':{gan:'己',ele:'土'},
  '申':{gan:'庚',ele:'金'},'酉':{gan:'辛',ele:'金'},'戌':{gan:'戊',ele:'土'},'亥':{gan:'壬',ele:'水'},
};

function computeLiuRen() {
  playDivinationSound();
  const name = document.getElementById('lrName').value || '有缘人';
  const dateStr = document.getElementById('lrDate').value;
  const hourVal = document.getElementById('lrHour').value;
  if (!dateStr || !hourVal) { showToast('请输入日期和时辰'); return; }

  const [year, month, day] = dateStr.split('-').map(Number);
  const hourNum = parseInt(hourVal);

  const dayStemIdx = getDayStemIndex(year, month, day);
  const dayBranchIdx = getDayBranchIndex(year, month, day);
  const dayStem = STEMS[dayStemIdx];
  const dayBranch = BRANCHES[dayBranchIdx];
  const hourBranchIdx = Math.floor(hourNum / 2) % 12;
  const hourBranch = BRANCHES[hourBranchIdx];

  // 六壬三传 (simplified: based on time)
  const stemIdx = dayStemIdx;
  const hourZhiIdx = hourBranchIdx;
  const dayZhiIdx = dayBranchIdx;

  // Simplified 三传: 发用 + 中传 + 末传
  const faYong = BRANCHES[(dayZhiIdx + hourZhiIdx) % 12];
  const zhongChuan = BRANCHES[(hourZhiIdx + dayZhiIdx) % 12];
  const moChuan = BRANCHES[(faYong ? BRANCHES.indexOf(faYong) : dayZhiIdx + 6) % 12];

  // 四课
  const ke1 = dayBranch;
  const ke2 = BRANCHES[(dayZhiIdx + 1) % 12];
  const ke3 = hourBranch;
  const ke4 = BRANCHES[(hourZhiIdx + 1) % 12];

  // 判断课体
  const tiGuan = getLiuRenTiGuan(faYong, zhongChuan, moChuan, dayStem);

  document.getElementById('lrMeta').textContent = `大六壬 · ${name} · ${year}年${month}月${day}日 ${hourBranch}时`;
  document.getElementById('lrSub').textContent = `日干${dayStem} · 日支${dayBranch} · 时支${hourBranch} · ${tiGuan.name}课`;

  const ctr = document.getElementById('lrInterp');
  ctr.innerHTML = '';

  // 大六壬 - 升级:专业级报告（四课详解+三传论断+课体分析+经典引用）
  
  // 大六壬经典引用
  const DALIU_CLASSIC = {
    siKe: '《大六壬大全》云:「四课者，日干阳、日干阴、日支阳、日支阴，四课完备，万事可断。」《六壬粹言》曰:「四课为六壬之根本，课体既成，吉凶可见。」',
    sanChuan: '《大六壬大全》云:「三传者，初传、中传、末传，事之始、中、终也。」《六壬指南》曰:「三传递义，吉凶可断。」',
    keTi: '《大六壬大全》云:「课体者，事之体也。伏吟反吟，各有其义。」《六壬粹言》曰:「课体既定，吉凶可知。」',
    ganZhi: '《大六壬大全》云:「日干为事主，日支为事体。」《六壬指南》曰:「干支配合，事体完备。」',
    liuShen: '《大六壬大全》云:「六神者，贵人、螣蛇、朱雀、六合、勾陈、青龙、天空、白虎、太常、玄武、太阴、天后也。」《六壬粹言》曰:「六神各有所主，配合三传，吉凶可见。」'
  };
  
  const blocks = [
    {
      title:'四 课 排 列',
      text: `第一课(日+日阴):${ke1} ${LR_ZHI_GAN[ke1]?.gan||dayStem}\n第二课(日阳+日):${ke2} ${LR_ZHI_GAN[ke2]?.gan||dayStem}\n第三课(辰+辰阴):${ke3} ${LR_ZHI_GAN[ke3]?.gan||dayStem}\n第四课(辰阳+辰):${ke4} ${LR_ZHI_GAN[ke4]?.gan||dayStem}\n\n${DALIU_CLASSIC.siKe}`,
      accent:'orange'
    },
    {
      title:'三 传 论 断',
      text: `发用(初传):${faYong} ${LR_ZHI_GAN[faYong]?.gan||dayStem}。此为事之端倪。\n中传:${zhongChuan} ${LR_ZHI_GAN[zhongChuan]?.gan||dayStem}。此为事之发展。\n末传:${moChuan} ${LR_ZHI_GAN[moChuan]?.gan||dayStem}。此为事之结果。\n\n${DALIU_CLASSIC.sanChuan}`,
      accent:'gold-accent'
    },
    {
      title:'课 体 论 断',
      text: `${tiGuan.name}:${tiGuan.desc}\n\n${DALIU_CLASSIC.keTi}`,
      accent:'violet-accent'
    },
    {
      title:'日 干 论 断',
      text: `日干${dayStem}(${ELE[dayStem]}属性),${getDayStemAnalysis(dayStem)}。${tiGuan.ganAdvice}\n\n${DALIU_CLASSIC.ganZhi}`,
      accent:'jade-accent'
    },
    {
      title:'六 神 配 合',
      text: getLiuRenShenPan(faYong, zhongChuan, moChuan, dayStem) + `\n\n${DALIU_CLASSIC.liuShen}`,
      accent:'cyan-accent'
    },
    {
      title:'综 合 建 议',
      text: `${tiGuan.advice}`,
      accent:'cinn-accent'
    },
    {
      title:'📜 经典出处',
      text: `${DALIU_CLASSIC.siKe}\n\n${DALIU_CLASSIC.sanChuan}\n\n${DALIU_CLASSIC.keTi}\n\n《大六壬大全·明·郭载騋》云:「大六壬为三式之首，以天盘地盘人盘三传，演万事之吉凶。」\n《六壬指南·清·程树勋》曰:「六壬之术，以四课三传为体，以六神为用，配合五行生克，万事可断。」`,
      accent:'gold-accent'
    },
  ];

  // 六壬断语
  var lrReadBox = document.getElementById('lrReadingBox');
  if (lrReadBox) lrReadBox.innerHTML = getLiurenReadingHTML(dayStem);

  document.getElementById('lrResult').classList.add('visible');
  document.getElementById('lrResult').scrollIntoView({ behavior: 'smooth' });
}

function getLiuRenTiGuan(fa, zhong, mo, dayStem) {
  const tiGuanMap = {
    '伏吟':'伏吟课，自静不动，宜守不宜动。诸事停滞，当静待时机。',
    '反吟':'反吟课，变动不居，诸事反复。宜随机应变，不宜固执。',
    '知一':'知一课，事在一处，选择明确。吉事在近，凶事在远。',
    '涉害':'涉害课，事多波折，涉历深重。需耐心处理，不可急躁。',
    '昴星':'昴星课，恐怖之象，有惊恐之事。宜防暗算，小心行事。',
    '别责':'别责课，独身无助，事需借助外力。',
    '八专':'八专课，事发专一，不涉他人。利主不利客。',
    '丁鬼':'丁鬼课，暗中变动，有突然之事。当防突然的变故。',
  };
  const idx = [fa,zhong,mo].map(b => BRANCHES.indexOf(b)).reduce((a,b)=>a+b,0);
  const keys = Object.keys(tiGuanMap);
  const name = keys[idx % keys.length];
  const desc = tiGuanMap[name];
  return {
    name,
    desc,
    ganAdvice: `日干${dayStem}在此课中，${desc}`,
    advice: `${desc} ${dayStem}为日主，当${getDayStemAdvice(dayStem)}。`,
  };
}

function getDayStemAnalysis(stem) {
  const analyses = {
    '甲':'如大树，有领导力，利东方发展。',
    '乙':'如花草，柔中有刚，利东方和东南。',
    '丙':'如太阳，热情洋溢，利南方发展。',
    '丁':'如灯火，内敛而明，利南方和西方。',
    '戊':'如高山，厚重踏实，利本地中央。',
    '己':'如田园，包容温和，利本地发展。',
    '庚':'如利剑，刚毅果敢，利西方发展。',
    '辛':'如珠玉，精致细腻，利西方发展。',
    '壬':'如大海，灵活变通，利北方发展。',
    '癸':'如雨露，柔顺内敛，利北方发展。',
  };
  return analyses[stem] || '';
}

function getDayStemAdvice(stem) {
  const advices = {
    '甲':'宜积极进取，不宜消极退缩。','乙':'宜柔中带刚，忌优柔寡断。',
    '丙':'宜主动出击，忌瞻前顾后。','丁':'宜内敛行事，忌张扬冒进。',
    '戊':'宜稳扎稳打，忌急功近利。','己':'宜广纳善言，忌独断专行。',
    '庚':'宜当机立断，忌犹豫不决。','辛':'宜谨慎细致，忌粗枝大叶。',
    '壬':'宜灵活变通，忌固执己见。','癸':'宜深思熟虑，忌盲目行动。',
  };
  return advices[stem] || '顺势而为';
}

function getLiuRenShenPan(fa, zhong, mo, dayStem) {
  const branchIdx = BRANCHES.indexOf(fa);
  const godSeq = ['青龙','玄武','白虎','勾陈','青龙','玄武','白虎','勾陈','青龙','玄武','白虎','勾陈'];
  const faGod = godSeq[branchIdx];
  const zhongGod = godSeq[(branchIdx+6)%12];
  const moGod = godSeq[(branchIdx+9)%12];
  const godInfo = {
    '青龙': LR_GODS.qinglong,
    '玄武': LR_GODS.xuanniao,
    '白虎': LR_GODS.baihu,
    '勾陈': LR_GODS.choutiger,
  };
  return `初传${fa}神${faGod}(${godInfo[faGod]?.nature||''}):${godInfo[faGod]?.desc||''}\n中传${zhong}神${zhongGod}(${godInfo[zhongGod]?.nature||''}):${godInfo[zhongGod]?.desc||''}\n末传${mo}神${moGod}(${godInfo[moGod]?.nature||''}):${godInfo[moGod]?.desc||''}`;
}

