// 显示案例库
function showCaseLibrary() {
  const modal = document.getElementById('caseLibraryModal');
  const content = document.getElementById('caseLibraryContent');

  let html = '';
  html += '<div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin-bottom:24px">';
  html += "<button onclick=\"filterCaseLibrary('all',this)\" style='padding:8px 18px;border:1px solid rgba(201,168,76,0.2);background:rgba(201,168,76,0.1);color:var(--gold);font-family:Noto Serif SC,serif;font-size:12px;letter-spacing:2px;cursor:pointer;border-radius:4px'>全部案例</button>";
  html += "<button onclick=\"filterCaseLibrary('career',this)\" style='padding:8px 18px;border:1px solid rgba(201,168,76,0.15);background:transparent;color:var(--paper2);font-family:Noto Serif SC,serif;font-size:12px;letter-spacing:2px;cursor:pointer;border-radius:4px'>事业运势</button>";
  html += "<button onclick=\"filterCaseLibrary('love',this)\" style='padding:8px 18px;border:1px solid rgba(201,168,76,0.15);background:transparent;color:var(--paper2);font-family:Noto Serif SC,serif;font-size:12px;letter-spacing:2px;cursor:pointer;border-radius:4px'>感情婚姻</button>";
  html += "<button onclick=\"filterCaseLibrary('health',this)\" style='padding:8px 18px;border:1px solid rgba(201,168,76,0.15);background:transparent;color:var(--paper2);font-family:Noto Serif SC,serif;font-size:12px;letter-spacing:2px;cursor:pointer;border-radius:4px'>健康养生</button>";
  html += "<button onclick=\"filterCaseLibrary('wealth',this)\" style='padding:8px 18px;border:1px solid rgba(201,168,76,0.15);background:transparent;color:var(--paper2);font-family:Noto Serif SC,serif;font-size:12px;letter-spacing:2px;cursor:pointer;border-radius:4px'>财运提升</button>";
  html += "<button onclick=\"filterCaseLibrary('study',this)\" style='padding:8px 18px;border:1px solid rgba(201,168,76,0.15);background:transparent;color:var(--paper2);font-family:Noto Serif SC,serif;font-size:12px;letter-spacing:2px;cursor:pointer;border-radius:4px'>学业考试</button>";
  html += '</div>';

  html += '<div id="caseLibraryGrid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(350px,1fr));gap:16px">';
  caseData.forEach(c => {
    html += generateCaseCard(c);
  });
  html += '</div>';

  content.innerHTML = html;
  modal.style.display = 'block';
}

// 生成案例卡片
function generateCaseCard(c) {
  return `
    <div class="case-card-item" data-type="${c.type}" style="padding:20px;background:rgba(255,255,255,0.02);border:1px solid rgba(201,168,76,0.1);border-radius:8px;cursor:pointer;transition:all .3s" onclick="toggleCaseDetail(${c.id})">
      <div style="display:inline-block;padding:4px 10px;background:rgba(201,168,76,0.08);border:1px solid rgba(201,168,76,0.2);color:var(--gold);font-size:11px;letter-spacing:2px;border-radius:3px;margin-bottom:10px">${c.badge}</div>
      <div style="font-family:\'Ma Shan Zheng\',serif;font-size:18px;letter-spacing:3px;margin-bottom:8px">${c.title}</div>
      <div style="font-size:12px;opacity:.6;line-height:1.7;letter-spacing:1px;margin-bottom:12px">${c.summary}</div>
      <div style="padding:8px 12px;background:rgba(39,174,96,0.05);border:1px solid rgba(39,174,96,0.15);border-radius:4px;font-size:12px;color:#2ecc71;letter-spacing:1px">${c.result}</div>
      <div class="case-detail-content" id="caseDetail${c.id}" style="display:none;margin-top:12px;padding:12px;background:rgba(201,168,76,0.03);border-radius:6px;font-size:12px;line-height:1.8;opacity:.7">
        <p><strong>📋 案例背景:</strong>${c.detail.background}</p>
        <p style="margin-top:8px"><strong>🔍 问题诊断:</strong>${c.detail.diagnosis}</p>
        <p style="margin-top:8px"><strong>💡 化解方法:</strong>${c.detail.solution}</p>
        <p style="margin-top:8px"><strong>📖 原理解析:</strong>${c.detail.principle}</p>
        <p style="margin-top:8px"><strong>⏱️ 化解过程:</strong>${c.detail.process}</p>
        <p style="margin-top:8px"><strong>📊 效果反馈:</strong>${c.detail.feedback}</p>
      </div>
    </div>
  `;
}

// 筛选案例库
function filterCaseLibrary(type, btn) {
  // 更新按钮状态
  btn.parentElement.querySelectorAll('button').forEach(b => {
    b.style.background = 'transparent';
    b.style.color = 'var(--paper2)';
    b.style.borderColor = 'rgba(201,168,76,0.15)';
  });
  btn.style.background = 'rgba(201,168,76,0.1)';
  btn.style.color = 'var(--gold)';
  btn.style.borderColor = 'rgba(201,168,76,0.2)';

  // 筛选
  const grid = document.getElementById('caseLibraryGrid');
  const cards = grid.querySelectorAll('.case-card-item');
  cards.forEach(card => {
    if (type === 'all' || card.getAttribute('data-type') === type) {
      card.style.display = 'block';
    } else {
      card.style.display = 'none';
    }
  });
}

// 切换案例详情
function toggleCaseDetail(id) {
  const detail = document.getElementById('caseDetail' + id);
  if (detail.style.display === 'none') {
    detail.style.display = 'block';
  } else {
    detail.style.display = 'none';
  }
}

// 关闭案例库
function closeCaseLibrary() {
  document.getElementById('caseLibraryModal').style.display = 'none';
}

// 在化解模块添加"查看案例库"按钮
document.addEventListener('DOMContentLoaded', function() {
  // 在化解模块的input-card后添加按钮
  const hjInputCard = document.querySelector('#section-huajie .input-card');
  if (hjInputCard) {
    const btn = document.createElement('button');
    btn.onclick = showCaseLibrary;
    btn.style.cssText = 'display:block;margin:16px auto 0;padding:12px 32px;background:transparent;border:1px solid rgba(201,168,76,0.3);color:var(--gold);font-family:\'Noto Serif SC\',serif;font-size:13px;letter-spacing:4px;cursor:pointer;border-radius:6px;transition:all .3s';
    btn.innerHTML = '📚 查看化解案例库';
    btn.onmouseover = function() { this.style.background = 'rgba(201,168,76,0.1)'; };
    btn.onmouseout = function() { this.style.background = 'transparent'; };
    hjInputCard.appendChild(btn);
  }
});


// ===== 引导区功能 =====
function toggleGuide() {
  const guideBanner = document.getElementById('guideBanner');
  if (guideBanner) {
    if (guideBanner.style.display === 'none') {
      guideBanner.style.display = 'block';
      localStorage.setItem('guideBannerHidden', 'false');
    } else {
      guideBanner.style.display = 'none';
      localStorage.setItem('guideBannerHidden', 'true');
    }
  }
}

// 页面加载时检查引导区状态
document.addEventListener('DOMContentLoaded', function() {
  const guideHidden = localStorage.getItem('guideBannerHidden');
  if (guideHidden === 'true') {
    const guideSection = document.getElementById('guideSection');
    if (guideSection) {
      guideSection.style.display = 'none';
    }
  }
});

// ===== 时辰选择功能 =====
function selectShichen(element) {
  // 移除其他选中状态
  document.querySelectorAll('.shichen-item').forEach(item => {
    item.classList.remove('selected');
    item.style.borderColor = 'rgba(201,168,76,0.12)';
    item.style.background = 'rgba(255,255,255,0.02)';
  });

  // 添加选中状态
  element.classList.add('selected');
  element.style.borderColor = 'var(--gold)';
  element.style.background = 'rgba(201,168,76,0.08)';

  // 获取时辰值
  const hour = element.getAttribute('data-hour');
  // console.log('选中时辰:', hour);

  // 可以在这里更新隐藏的input值
  const hjHourInput = document.getElementById('hjHour');
  if (hjHourInput) {
    hjHourInput.value = hour;
  }
}

// ===== 性别选择功能 =====
function selectSex(sex) {
  const maleCard = document.getElementById('sexMaleCard');
  const femaleCard = document.getElementById('sexFemaleCard');

  if (!maleCard || !femaleCard) return;

  if (sex === 'male') {
    maleCard.style.background = 'rgba(201,168,76,0.08)';
    maleCard.style.borderColor = 'var(--gold)';
    maleCard.querySelector('div:nth-child(2)').style.color = 'var(--gold)';

    femaleCard.style.background = 'rgba(255,255,255,0.02)';
    femaleCard.style.borderColor = 'rgba(201,168,76,0.15)';
    femaleCard.querySelector('div:nth-child(2)').style.color = 'var(--paper2)';

    // 更新隐藏的性别input
    const sexInput = document.getElementById('baziSex');
    if (sexInput) sexInput.value = 'male';
    const hjSexInput = document.getElementById('hjSex');
    if (hjSexInput) hjSexInput.value = 'male';
  } else {
    femaleCard.style.background = 'rgba(201,168,76,0.08)';
    femaleCard.style.borderColor = 'var(--gold)';
    femaleCard.querySelector('div:nth-child(2)').style.color = 'var(--gold)';

    maleCard.style.background = 'rgba(255,255,255,0.02)';
    maleCard.style.borderColor = 'rgba(201,168,76,0.15)';
    maleCard.querySelector('div:nth-child(2)').style.color = 'var(--paper2)';

    // 更新隐藏的性别input
    const sexInput = document.getElementById('baziSex');
    if (sexInput) sexInput.value = 'female';
    const hjSexInput = document.getElementById('hjSex');
    if (hjSexInput) hjSexInput.value = 'female';
  }
}

// ===== 案例筛选功能 =====
function filterCases(type, btn) {
  // 更新按钮状态
  if (btn && btn.parentElement) {
    btn.parentElement.querySelectorAll('button').forEach(b => {
      b.style.background = 'transparent';
      b.style.color = 'var(--paper2)';
      b.style.borderColor = 'rgba(201,168,76,0.15)';
    });
    btn.style.background = 'rgba(201,168,76,0.1)';
    btn.style.color = 'var(--gold)';
    btn.style.borderColor = 'rgba(201,168,76,0.2)';
  }

  // 筛选案例(如果在案例库modal中)
  const modal = document.getElementById('caseLibraryModal');
  if (modal && modal.style.display === 'block') {
    const grid = document.getElementById('caseLibraryGrid');
    if (grid) {
      const cards = grid.querySelectorAll('.case-card-item');
      cards.forEach(card => {
        if (type === 'all' || card.getAttribute('data-type') === type) {
          card.style.display = 'block';
        } else {
          card.style.display = 'none';
        }
      });
    }
  }
}

// ===== 优化的化解方案展示格式 =====
function displayHuajieFriendly(data) {
  // 这个函数可以被 computeHuajie() 调用,以"缘主友好"格式展示化解方案
  // data 应包含:problem, analysis, solutions, warnings, checklist

  let html = '';
  html += '<div style="background:rgba(255,255,255,0.02);border:1px solid rgba(201,168,76,0.15);border-radius:12px;padding:30px;margin-bottom:24px">';

  // 问题部分
  html += '<div style="font-size:16px;letter-spacing:2px;color:var(--paper);margin-bottom:20px;padding-bottom:20px;border-bottom:1px solid rgba(201,168,76,0.1);line-height:1.8">';
  html += '<strong>📌 您的问题:</strong>' + (data.problem || '待分析') + '<br>';
  html += '<strong>⚠️ 根源分析:</strong>' + (data.analysis || '待分析');
  html += '</div>';

  // 化解方案
  html += '<div style="margin-top:24px">';
  html += '<div style="font-size:18px;letter-spacing:4px;color:var(--gold);margin-bottom:20px;font-weight:600">💡 化解方案(按优先级排列)</div>';

  if (data.solutions && data.solutions.length > 0) {
    html += '<ul style="list-style:none;padding:0">';
    data.solutions.forEach((s, i) => {
      html += '<li style="padding:18px;background:rgba(255,255,255,0.03);border:1px solid rgba(201,168,76,0.08);border-radius:8px;margin-bottom:14px">';
      html += '<div style="display:flex;align-items:flex-start;gap:12px">';
      html += '<span style="display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;background:var(--gold);color:var(--ink);border-radius:50%;font-size:14px;font-weight:bold;flex-shrink:0">' + (i+1) + '</span>';
      html += '<div style="flex:1">';
      html += '<div style="font-size:16px;letter-spacing:2px;color:var(--paper);margin-bottom:8px;font-weight:600">' + s.title + '</div>';
      html += '<div style="font-size:14px;opacity:0.7;line-height:1.8;letter-spacing:1px;margin-left:40px">' + s.desc + '</div>';
      if (s.principle) {
        html += '<div style="font-size:12px;opacity:0.5;letter-spacing:1px;margin-top:10px;margin-left:40px;padding:10px 14px;background:rgba(201,168,76,0.04);border-left:3px solid var(--gold);border-radius:4px;line-height:1.7">📖 ' + s.principle + '</div>';
      }
      html += '</div>';
      html += '</div>';
      html += '</li>';
    });
    html += '</ul>';
  }

  html += '</div>';

  // 注意事项
  if (data.warnings && data.warnings.length > 0) {
    html += '<div style="background:rgba(231,76,60,0.06);border:1px solid rgba(231,76,60,0.2);border-radius:8px;padding:18px;margin-top:20px">';
    html += '<div style="color:#e74c3c;font-size:15px;letter-spacing:2px;margin-bottom:8px;font-weight:600">⚠️ 注意事项(重要)</div>';
    html += '<div style="font-size:14px;line-height:2;opacity:0.8;letter-spacing:1px">';
    data.warnings.forEach(w => {
      html += '<p>' + w + '</p>';
    });
    html += '</div></div>';
  }

  // 自评清单
  html += '<div style="margin-top:24px;padding:20px;background:rgba(201,168,76,0.05);border:1px solid rgba(201,168,76,0.15);border-radius:8px">';
  html += '<div style="font-size:16px;letter-spacing:3px;color:var(--gold);margin-bottom:16px">📋 化解效果自评</div>';
  html += '<div style="font-size:14px;opacity:0.75;letter-spacing:1px;line-height:2">';
  html += '<label style="display:flex;align-items:center;gap:10px;padding:8px 0;cursor:pointer;border-bottom:1px solid rgba(201,168,76,0.06)"><input type="checkbox" style="accent-color:var(--gold);width:18px;height:18px"> 1个月后自评</label>';
  html += '<label style="display:flex;align-items:center;gap:10px;padding:8px 0;cursor:pointer;border-bottom:1px solid rgba(201,168,76,0.06)"><input type="checkbox" style="accent-color:var(--gold);width:18px;height:18px"> 3个月后自评</label>';
  html += '<label style="display:flex;align-items:center;gap:10px;padding:8px 0;cursor:pointer"><input type="checkbox" style="accent-color:var(--gold);width:18px;height:18px"> 6个月后自评</label>';
  html += '</div></div>';

  html += '</div>';

  return html;
}

// ===== 术语高亮 =====
function highlightTerms(text) {
  const terms = {
    '甲': '甲木，阳木，代表大树、栋梁',
    '乙': '乙木，阴木，代表花草、藤蔓',
    '丙': '丙火，阳火，代表太阳、光明',
    '丁': '丁火，阴火，代表灯火、烛光',
    '戊': '戊土，阳土，代表高山、大地',
    '己': '己土，阴土，代表田园、泥土',
    '庚': '庚金，阳金，代表刀剑、金属',
    '辛': '辛金，阴金，代表首饰、珠宝',
    '壬': '壬水，阳水，代表大海、江河',
    '癸': '癸水，阴水，代表雨露、泉水',
    '子': '子水，代表智慧、变通',
    '午': '午火，代表热情、能量',
    '日主': '八字中的日干，代表命主本人',
    '大运': '每10年一换的运势周期',
    '流年': '当年的运势',
    '食伤': '食神和伤官的统称，代表才华、创造力',
    '财星': '正财和偏财，代表财富、收入',
    '官星': '正官和七杀，代表事业、权力',
    '印星': '正印和偏印，代表学业、贵人',
    '比劫': '比肩和劫财，代表朋友、竞争',
    '渊海子平': '宋代徐大升所著命理经典',
    '滴天髓': '清代命理经典，以理论精深著称',
    '三命通会': '明代万民英所著命理百科全书',
    '黄帝内经': '中医经典，也涉及五行养生'
  };

  let highlighted = text;
  Object.keys(terms).forEach(term => {
    const regex = new RegExp(term, 'g');
    highlighted = highlighted.replace(regex, '<span class="term-highlight" title="' + terms[term] + '">' + term + '</span>');
  });

  return highlighted;
}

