// ================================================================
// 谐音检测
// ================================================================
function checkXieyin(fullName) {
  const result = [];

  for (const item of XIEYIN_DB) {
    // 简单检测:如果名字中包含谐音词的字符
    if (fullName.includes(item.word[0]) && fullName.includes(item.word[1])) {
      result.push({
        word: item.word,
        meaning: item.meaning
      });
    }
  }

  return result;
}

