  html += '<p style="margin:0;color:var(--paper2)">' + info.bestMatch.join('、') + '</p>';
  html += '</div>';
  
  html += '<div style="background:rgba(244,67,54,0.08);padding:16px;border-radius:12px;margin-bottom:16px">';
